import{_ as t,o as r,c as n,a3 as o}from"./chunks/framework.CjquFG0V.js";const c=JSON.parse('{"title":"27A. Transition To Retirement","description":"","frontmatter":{"title":"27A. Transition To Retirement","eba":"Mental Health Services 2024-2028","topics":["flexible-work","preliminary"]},"headers":[],"relativePath":"ebas/mental-health/common-terms/employment-types/27A-transition-to-retirement.md","filePath":"ebas/mental-health/common-terms/employment-types/27A-transition-to-retirement.md"}'),a={name:"ebas/mental-health/common-terms/employment-types/27A-transition-to-retirement.md"};function i(s,e,p,l,m,h){return r(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="_27a-transition-to-retirement" tabindex="-1">27A. Transition To Retirement <a class="header-anchor" href="#_27a-transition-to-retirement" aria-label="Permalink to &quot;27A. Transition To Retirement&quot;">​</a></h1><p><strong>27A.1</strong> An Employee may advise their Employer in writing of their intention to retire within the next five years and participate in a retirement transition arrangement.</p><p><strong>27A.2</strong> Transition to retirement arrangements may be proposed and, where agreed, implemented as:</p><p><strong>(a)</strong> a flexible working arrangement (see <a href="/eba/ebas/mental-health/common-terms/workplace-rights/65-flexible-working-arrangements.html">clause 65</a> Flexible Working Arrangements);</p><p><strong>(b)</strong> in writing between the parties; or</p><p><strong>(c)</strong> any combination of the above.</p><p><strong>27A.3</strong> A transition to retirement arrangement may include but is not limited to:</p><p><strong>(a)</strong> a reduction in their EFT</p><p><strong>(b)</strong> a job share arrangement; or</p><p><strong>(c)</strong> working in a position at a lower classification or rate of pay.</p><p><strong>27A.4</strong> The Employer will consider, and not unreasonably refuse, a request by an Employee who wishes to transition to retirement:</p><p><strong>(a)</strong> to use accrued Long Service Leave (LSL) or Annual Leave for the purpose of reducing the number of days worked per week while retaining their previous employment status; or</p><p><strong>(b)</strong> that will facilitate an Employee&#39;s finishing date as being at the conclusion of any amount of accrued annual leave or LSL the Employee seeks to take where the Employee provides a definite finishing date; or</p><p><strong>(c)</strong> to be appointed to a role which that has a lower hourly rate of pay or reduced hours (post transition role), in which case:</p><p><strong>(i)</strong> the Employer will preserve the accrual of LSL at the time of reduction in salary or hours; and</p><p><strong>(ii)</strong> where LSL is taken or paid out in lieu of termination, the Employee will be paid LSL hours at the applicable classification and grade, and at the preserved hours, prior to the post transition role until the preserved LSL hours are exhausted.</p><p>Plain language terms: phased retirement, winding down, TTR.</p>',17)])])}const d=t(a,[["render",i]]);export{c as __pageData,d as default};
